{"content":"use crate::api::*;
use crate::distance::l2_distance;
use rayon::prelude::*;
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use std::sync::RwLock;

struct Storage {
    ids: Vec<u64>,
    vectors: Vec<f32>,
    dim: usize,
}

pub struct VectorDB {
    data: RwLock<Storage>,
}

impl VectorDB {
    pub fn new() -> Self {
        let _ = rayon::ThreadPoolBuilder::new().num_threads(4).build_global();
        Self {
            data: RwLock::new(Storage {
                ids: Vec::new(),
                vectors: Vec::new(),
                dim: 128,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        data.ids.reserve(count);
        data.vectors.reserve(count * data.dim);
        for (id, vector) in vectors {
            data.ids.push(id);
            data.vectors.extend_from_slice(&vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let k = top_k as usize;
        if k == 0 || data.ids.is_empty() {
            return Vec::new();
        }

        let dim = data.dim;
        let ids = &data.ids;
        let vectors = &data.vectors;

        let heap = (0..ids.len())
            .into_par_iter()
            .fold(
                || BinaryHeap::with_capacity(k + 1),
                |mut heap, i| {
                    let offset = i * dim;
                    let distance = l2_distance(vector, &vectors[offset..offset + dim]) as f32;
                    if heap.len() < k {
                        heap.push(HeapItem { distance, id: ids[i] });
                    } else if let Some(top) = heap.peek() {
                        if distance < top.distance {
                            heap.pop();
                            heap.push(HeapItem { distance, id: ids[i] });
                        }
                    }
                    heap
                },
            )
            .reduce(
                || BinaryHeap::with_capacity(k + 1),
                |mut left, mut right| {
                    while let Some(item) = right.pop() {
                        if left.len() < k {
                            left.push(item);
                        } else if let Some(top) = left.peek() {
                            if item.distance < top.distance {
                                left.pop();
                                left.push(item);
                            }
                        }
                    }
                    left
                },
            );

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance as f64,
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}

