use crate::api::*;
use crate::distance::l2_distance;
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use std::sync::RwLock;

struct VectorEntry {
    id: u64,
    vector: Vec<f32>,
}

pub struct VectorDB {
    data: RwLock<Vec<VectorEntry>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.push(VectorEntry { id, vector });
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        data.extend(vectors.into_iter().map(|(id, vector)| VectorEntry { id, vector }));
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let k = top_k as usize;
        if k == 0 {
            return Vec::new();
        }

        let mut heap: BinaryHeap<HeapItem> = BinaryHeap::with_capacity(k + 1);
        for entry in data.iter() {
            let distance = l2_distance(vector, &entry.vector);
            if heap.len() < k {
                heap.push(HeapItem { distance, id: entry.id });
            } else if let Some(top) = heap.peek() {
                if distance < top.distance {
                    heap.pop();
                    heap.push(HeapItem { distance, id: entry.id });
                }
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance,
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}

#[derive(Debug)]
struct HeapItem {
    distance: f64,
    id: u64,
}

impl Eq for HeapItem {}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance && self.id == other.id
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.distance
            .partial_cmp(&other.distance)
            .unwrap_or(Ordering::Equal)
    }
}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for (x, y) in a.iter().zip(b.iter()) {
        let diff = *x as f64 - *y as f64;
        sum += diff * diff;
    }
    sum
}

