        data.vectors.reserve(count * dim);
        for (id, vector) in vectors {
            data.ids.push(id);
            data.vectors.extend_from_slice(&vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let k = top_k as usize;
        if k == 0 || data.ids.is_empty() {
            return Vec::new();
        }

        let dim = data.dim;
        let ids = &data.ids;
        let vectors = &data.vectors;

        let heap = (0..ids.len())
            .into_par_iter()
            .fold(
                || BinaryHeap::with_capacity(k + 1),
                |mut heap, i| {
                    let offset = i * dim;
                    let distance = l2_distance(vector, &vectors[offset..offset + dim]) as f32;
                    if heap.len() < k {
                        heap.push(HeapItem { distance, id: ids[i] });
                    } else if let Some(top) = heap.peek() {
                        if distance < top.distance {
                            heap.pop();
                            heap.push(HeapItem { distance, id: ids[i] });
                        }
                    }
                    heap
                },
            )
            .reduce(
                || BinaryHeap::with_capacity(k + 1),
                |mut left, mut right| {
                    while let Some(item) = right.pop() {
                        if left.len() < k {
                            left.push(item);
                        } else if let Some(top) = left.peek() {
                            if item.distance < top.distance {
                                left.pop();
                                left.push(item);
                            }
                        }
                    }
                    left
                },
            );

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance as f64,
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}

#[derive(Debug)]
struct HeapItem {
    distance: f32,
    id: u64,
}

impl Eq for HeapItem {}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance && self.id == other.id
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.distance
            .partial_cmp(&other.distance)
            .unwrap_or(Ordering::Equal)
    }
}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

#[derive(Copy, Clone)]
pub enum DistanceKind {
    Avx512,
    Avx2,
    Scalar,
}

pub fn select_distance_kind() -> DistanceKind {
    #[cfg(target_arch = "x86_64")]
    {
        if std::is_x86_feature_detected!("avx512f") {
            return DistanceKind::Avx512;
        }
        if std::is_x86_feature_detected!("avx2") {
            return DistanceKind::Avx2;
        }
    }
    DistanceKind::Scalar
}

#[inline(always)]
pub fn l2_distance_with(kind: DistanceKind, a: &[f32], b: &[f32]) -> f32 {
    match kind {
        DistanceKind::Avx512 => unsafe { l2_distance_avx512(a, b) },
        DistanceKind::Avx2 => unsafe { l2_distance_avx2(a, b) },
        DistanceKind::Scalar => l2_distance_scalar(a, b),
    }
}

#[inline(always)]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    for (x, y) in a.iter().zip(b.iter()) {
        let diff = x - y;
        sum += diff * diff;
    }
    sum
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::x86_64::*;
    let mut sum = _mm512_setzero_ps();
    let mut i = 0;
    while i + 16 <= a.len() {
        let av = _mm512_loadu_ps(a.as_ptr().add(i));
        let bv = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(av, bv);
        let prod = _mm512_mul_ps(diff, diff);
        sum = _mm512_add_ps(sum, prod);
        i += 16;
    }
    let mut total = _mm512_reduce_add_ps(sum);
    while i < a.len() {
        let diff = a.get_unchecked(i) - b.get_unchecked(i);
        total += diff * diff;
        i += 1;
    }
    total
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::x86_64::*;
    let mut sum = _mm256_setzero_ps();
    let mut i = 0;
    while i + 8 <= a.len() {
        let av = _mm256_loadu_ps(a.as_ptr().add(i));
        let bv = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff = _mm256_sub_ps(av, bv);
        let prod = _mm256_mul_ps(diff, diff);
        sum = _mm256_add_ps(sum, prod);
        i += 8;
    }
    let mut tmp = [0f32; 8];
    _mm256_storeu_ps(tmp.as_mut_ptr(), sum);
    let mut total: f32 = tmp.iter().sum();
    while i < a.len() {
        let diff = a.get_unchecked(i) - b.get_unchecked(i);
        total += diff * diff;
        i += 1;
    }
    total
}

